// Normalize the incoming Shopify-style "checkout abandoned" payload
const input = $input.first().json;
const b = input.body || input;          // n8n puts the JSON body under .body

const items = Array.isArray(b.cart_items) ? b.cart_items : [];

// plain-text list for the LLM prompt
const items_text = items
  .map(i => `- ${i.name || i.title || 'Item'}: ${i.price ?? ''}`)
  .join('\n');

// HTML rows for the email template (2 columns: name | price)
const items_html = items
  .map(i => `<tr><td style="padding:8px 0;border-bottom:1px solid #eee;color:#333;font-size:14px;">${i.name || i.title || 'Item'}</td><td style="padding:8px 0;border-bottom:1px solid #eee;color:#333;font-size:14px;text-align:right;white-space:nowrap;">${i.price ?? ''}</td></tr>`)
  .join('');

// demo override: pass "delay_minutes" in the payload to fire sooner. Defaults to 60 (= 1 hour).
const delay_minutes = Number(b.delay_minutes) > 0 ? Number(b.delay_minutes) : 60;

const customer_name = b.customer_name || 'there';

const llm_messages = [
  { role: 'system', content: 'You write short, warm, non-pushy abandoned-cart recovery email body copy for an online store. Output ONLY 2-3 short paragraphs of body text (90-130 words). No subject line, no greeting like Hi or Hello, no sign-off or signature, no markdown, no fake discounts. Gently remind them their items are saved and invite them to finish checking out.' },
  { role: 'user', content: `Customer first name: ${customer_name}\nCart total: ${b.cart_total ?? ''}\nItems:\n${items_text || '- (no items provided)'}\n\nWrite the recovery email body.` }
];

return [{ json: {
  customer_name,
  customer_email: b.customer_email || '',
  customer_phone: b.customer_phone || '',
  cart_total: b.cart_total ?? '',
  checkout_url: b.checkout_url || '#',
  items_text,
  items_html,
  delay_minutes,
  llm_messages
} }];

// Combine the LLM-written copy with a clean, image-free HTML template
const data = $('Prepare Data').item.json;

let copy;
try {
  copy = $json.choices[0].message.content.trim();
} catch (e) {
  copy = `We noticed you left a few things in your cart, and we saved them for you. Whenever you are ready, you can pick up right where you left off. If you have any questions about your order, just reply to this email and we will be glad to help.`;
}

const copy_html = copy
  .split(/\n\s*\n/)
  .map(p => `<p style="margin:0 0 16px;line-height:1.6;color:#333;font-size:15px;">${p.replace(/\n/g, '<br>')}</p>`)
  .join('');

const name = data.customer_name || 'there';
const subject = `${name}, you left something in your cart`;

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#f4f4f7;font-family:Arial,Helvetica,sans-serif;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f7;padding:24px 0;"><tr><td align="center">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:520px;background:#ffffff;border-radius:12px;border:1px solid #ececf1;">
<tr><td style="padding:28px 32px 8px;"><h1 style="margin:0;font-size:20px;color:#111;">Hi ${name}, your cart misses you</h1></td></tr>
<tr><td style="padding:8px 32px 0;">${copy_html}</td></tr>
<tr><td style="padding:8px 32px 0;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0">
<tr><td colspan="2" style="padding-top:12px;font-size:12px;color:#888;text-transform:uppercase;letter-spacing:.5px;">Your cart</td></tr>
${data.items_html}
<tr><td style="padding:12px 0 0;font-weight:bold;color:#111;font-size:15px;">Total</td><td style="padding:12px 0 0;font-weight:bold;color:#111;font-size:15px;text-align:right;">${data.cart_total}</td></tr>
</table></td></tr>
<tr><td align="center" style="padding:28px 32px;"><a href="${data.checkout_url}" style="background:#111;color:#fff;text-decoration:none;padding:14px 32px;border-radius:8px;font-size:15px;font-weight:bold;display:inline-block;">Complete your order</a></td></tr>
<tr><td style="padding:0 32px 28px;"><p style="margin:0;font-size:12px;color:#aaaaaa;line-height:1.5;">You are receiving this because you started a checkout with us. If this was not you, please ignore this email.</p></td></tr>
</table></td></tr></table></body></html>`;

return [{ json: {
  email_subject: subject,
  email_html: html,
  customer_email: data.customer_email,
  customer_name: name,
  cart_total: data.cart_total
} }];

// Append a row to a local CSV log (no OAuth needed). status = sent
const fs = require('fs');
const path = '/home/node/.n8n/cart_recovery_log.csv';
const data = $('Prepare Data').item.json;
const esc = v => '"' + String(v ?? '').replace(/"/g, '""') + '"';
if (!fs.existsSync(path)) {
  fs.writeFileSync(path, 'timestamp,customer_name,customer_email,cart_total,status\n');
}
const row = [new Date().toISOString(), data.customer_name, data.customer_email, data.cart_total, 'sent'].map(esc).join(',') + '\n';
fs.appendFileSync(path, row);
return [{ json: { logged: true, status: 'sent', file: path } }];

